def _status_card_surface_is_nonblocking(status: Any) -> bool:
    return status in {PASS, "clear", "actionable"}


def _compact_first_contact_surface_refs(first_screen: dict[str, Any]) -> dict[str, Any]:
    refs = first_screen.get("first_contact_surface_refs")
    if not isinstance(refs, dict):
        return {}

    surfaces = refs.get("surfaces")
    if not isinstance(surfaces, dict):
        surfaces = {}

    required_surface_ids = [
        surface_id
        for surface_id in refs.get("required_surface_ids", [])
        if isinstance(surface_id, str)
    ]
    surface_keys_by_id = {
        "route": ["state_ref", "selected_route_ref", "status_ref"],
        "work": ["state_ref", "selected_work_ref", "event_ref"],
        "events": ["state_ref", "status_ref"],
        "evidence": [
            "state_ref",
            "index_ref",
            "body_text_exported",
        ],
        "graph": ["state_ref", "status_ref"],
        "observatory": [
            "bounded_validation_request_count",
            "compact_endpoint",
            "expanded_endpoint",
        ],
        "proof_lab": ["endpoint", "route_id", "receipt_ref"],
        "status": [
            "endpoint",
            "body_import_floor_ref",
            "workingness_command",
        ],
    }
    compact_surfaces: dict[str, dict[str, Any]] = {}
    for surface_id in required_surface_ids:
        surface = surfaces.get(surface_id)
        if not isinstance(surface, dict):
            continue
        compact_surfaces[surface_id] = {
            key: surface[key]
            for key in surface_keys_by_id.get(surface_id, [])
            if key in surface
        }

    safe_to_show = refs.get("safe_to_show")
    if not isinstance(safe_to_show, dict):
        safe_to_show = {}

    return {
        "schema_version": "microcosm_tour_card_first_contact_surface_refs_v1",
        "source_ref": "microcosm first-screen <project>::first_contact_surface_refs",
        "command_refs": {
            "observe": "microcosm observe <project>",
            "status_card": "microcosm status --card <project>",
            "observatory_bounded": OBSERVATORY_BOUNDED_VALIDATION_COMMAND,
            "proof_lab": PROOF_LAB_FIRST_SCREEN_COMMAND,
        },
        "reader_rule": refs.get("reader_rule"),
        "required_surface_ids": required_surface_ids,
        "surface_count": len(compact_surfaces),
        "surfaces": compact_surfaces,
        "safe_to_show": {
            key: safe_to_show.get(key)
            for key in [
                "project_local_state_refs_visible",
                "receipt_refs_visible",
                "body_text_exported",
                "source_files_mutated",
                "provider_calls_authorized",
                "release_authorized",
                "proof_correctness_claim",
            ]
            if key in safe_to_show
        },
        "authority": refs.get("authority"),
    }


def _compact_tour_card_body_floor_defects(
    defect_preview: object,
    *,
    limit: int = STATUS_CARD_DEFECT_PREVIEW_LIMIT,
) -> list[dict[str, Any]]:
    if not isinstance(defect_preview, list):
        return []

    compact: list[dict[str, Any]] = []
    for defect in defect_preview[:limit]:
        if not isinstance(defect, dict):
            continue
        compact.append(
            {
                "material_id": defect.get("material_id"),
                "material_class": defect.get("material_class"),
                "target_ref": defect.get("target_ref"),
                "defect_codes": defect.get("defect_codes", []),
                "body_text_in_receipt": defect.get("body_in_receipt") is True,
            }
        )
    return compact


def _compact_body_import_defects(
    body_floor: dict[str, Any],
    *,
    limit: int = STATUS_CARD_DEFECT_PREVIEW_LIMIT,
) -> list[dict[str, Any]]:
    defects = body_floor.get("defects", [])
    if not isinstance(defects, list):
        return []

    imports_by_material_id = {
        str(row.get("material_id")): row
        for row in body_floor.get("body_imports", [])
        if isinstance(row, dict) and row.get("material_id")
    }
    preview: list[dict[str, Any]] = []
    for defect in defects:
        if not isinstance(defect, dict):
            continue
        material_id = defect.get("material_id")
        import_row = imports_by_material_id.get(str(material_id))
        import_row = import_row if isinstance(import_row, dict) else {}
        defect_codes = defect.get("defect_codes", [])
        if not isinstance(defect_codes, list):
            defect_codes = []
        source_refs = import_row.get("source_refs", [])
        if not isinstance(source_refs, list):
            source_refs = []
        validation_refs = import_row.get("validation_refs", [])
        if not isinstance(validation_refs, list):
            validation_refs = []
        preview.append(
            {
                "material_id": material_id,
                "material_class": defect.get("material_class"),
                "target_ref": defect.get("target_ref"),
                "defect_codes": [
                    str(code) for code in defect_codes if isinstance(code, str)
                ],
                "source_refs": [
                    str(ref) for ref in source_refs if isinstance(ref, str)
                ][:STATUS_CARD_FAMILY_REF_PREVIEW_LIMIT],
                "validation_refs": [
                    str(ref) for ref in validation_refs if isinstance(ref, str)
                ][:STATUS_CARD_FAMILY_REF_PREVIEW_LIMIT],
                "verification_mode": import_row.get("verification_mode"),
                "body_text_in_receipt": defect.get("body_in_receipt") is True,
            }
        )
        if len(preview) >= limit:
            break
    return preview


def _status_card_front_door_status(card: dict[str, Any]) -> dict[str, Any]:
    front_door = (
        card.get("front_door", {})
        if isinstance(card.get("front_door"), dict)
        else {}
    )
    route_explanation = (
        front_door.get("route_explanation", {})
        if isinstance(front_door.get("route_explanation"), dict)
        else {}
    )
    route_selection_proof = (
        front_door.get("route_selection_proof", {})
        if isinstance(front_door.get("route_selection_proof"), dict)
        else {}
    )
    state_write_proof = (
        front_door.get("state_write_proof", {})
        if isinstance(front_door.get("state_write_proof"), dict)
        else {}
    )
    workingness = (
        card.get("workingness", {})
        if isinstance(card.get("workingness"), dict)
        else {}
    )
    surfaces: dict[str, Any] = {}

    def add_surface(surface_id: str, status: Any) -> None:
        if status is not None:
            surfaces[surface_id] = status

    add_surface("runtime_status", card.get("status"))
    add_surface("project_state", front_door.get("project_state_status"))
    add_surface("route_selection_proof", route_selection_proof.get("status"))
    add_surface("route_explanation", route_explanation.get("status"))
    add_surface("state_write_proof", state_write_proof.get("status"))
    add_surface(
        "macro_body_import_floor",
        (card.get("macro_body_import_floor") or {}).get("status")
        if isinstance(card.get("macro_body_import_floor"), dict)
        else None,
    )
    add_surface(
        "workingness_map_generation",
        workingness.get("map_generation_status"),
    )
    add_surface(
        "workingness_failure_envelope",
        workingness.get("failure_envelope_status"),
    )
    add_surface(
        "proof_lab",
        (card.get("proof_lab") or {}).get("status")
        if isinstance(card.get("proof_lab"), dict)
        else None,
    )
    proof_lab_cache_status = (
        (card.get("proof_lab") or {}).get("cache_status")
        if isinstance(card.get("proof_lab"), dict)
        else None
    )
    if proof_lab_cache_status == "stale_cached_receipt":
        add_surface("proof_lab_cache", "actionable")
    elif proof_lab_cache_status == "missing_cached_receipt":
        add_surface("proof_lab_cache", proof_lab_cache_status)
    elif proof_lab_cache_status is not None:
        add_surface("proof_lab_cache", PASS)
    add_surface(
        "observatory",
        (front_door.get("observatory") or {}).get("status")
        if isinstance(front_door.get("observatory"), dict)
        else None,
    )
    add_surface(
        "payload_boundary_audit",
        (card.get("payload_boundary_audit") or {}).get("status")
        if isinstance(card.get("payload_boundary_audit"), dict)
        else None,
    )
    blocking_surface_ids = [
        surface_id
        for surface_id, surface_status in surfaces.items()
        if not _status_card_surface_is_nonblocking(surface_status)
    ]
    actionable_surface_ids = [
        surface_id
        for surface_id, surface_status in surfaces.items()
        if surface_status == "actionable"
    ]
    blocking_surface_details: dict[str, dict[str, Any]] = {}
    for surface_id in blocking_surface_ids:
        detail: dict[str, Any] = {"status": surfaces.get(surface_id)}
        if surface_id == "runtime_status":
            detail.update(
                {
                    "reason": (
                        "Top-level runtime status mirrors blocking "
                        "first-screen surfaces; inspect the named detail rows."
                    ),
                    "derived_blocking_surface_ids": [
                        item for item in blocking_surface_ids if item != surface_id
                    ],
                }
            )
        elif surface_id == "macro_body_import_floor":
            body_floor = (
                card.get("macro_body_import_floor", {})
                if isinstance(card.get("macro_body_import_floor"), dict)
                else {}
            )
            detail.update(
                {
                    "defect_count": body_floor.get("defect_count"),
                    "defect_preview": body_floor.get("defect_preview", []),
                    "defect_preview_limit": body_floor.get(
                        "defect_preview_limit",
                        STATUS_CARD_DEFECT_PREVIEW_LIMIT,
                    ),
                    "full_status_ref": body_floor.get(
                        "full_status_ref",
                        "microcosm status::macro_body_import_floor",
                    ),
                    "full_defects_ref": body_floor.get(
                        "full_defects_ref",
                        "microcosm status::macro_body_import_floor.defects",
                    ),
                }
            )
        elif surface_id == "project_state":
            project_state = (
                front_door.get("project_state", {})
                if isinstance(front_door.get("project_state"), dict)
                else {}
            )
            recovery = project_state.get("recovery")
            if not isinstance(recovery, dict):
                recovery = (
                    front_door.get("project_recovery", {})
                    if isinstance(front_door.get("project_recovery"), dict)
                    else {}
                )
            detail.update(
                {
                    "state_dir_exists": project_state.get("state_dir_exists"),
                    "existing_state_ref_count": project_state.get(
                        "existing_state_ref_count"
                    ),
                    "route_count": project_state.get("route_count"),
                    "primary_recovery_command": recovery.get("primary_command"),
                    "status_after_recovery_command": recovery.get(
                        "status_after_recovery_command"
                    ),
                    "recovery": recovery,
                    "reader_action": (
                        recovery.get("reason")
                        or "Run the project recovery command, then rerun the status card."
                    ),
                }
            )
        elif surface_id == "state_write_proof":
            project_state = (
                front_door.get("project_state", {})
                if isinstance(front_door.get("project_state"), dict)
                else {}
            )
            recovery = project_state.get("recovery")
            if not isinstance(recovery, dict):
                recovery = (
                    front_door.get("project_recovery", {})
                    if isinstance(front_door.get("project_recovery"), dict)
                    else {}
                )
            detail.update(
                {
                    "state_dir_exists": state_write_proof.get("state_dir_exists"),
                    "state_file_count": state_write_proof.get("state_file_count"),
                    "missing_state_refs": state_write_proof.get(
                        "missing_state_refs", []
                    ),
                    "state_write_result_ref": state_write_proof.get(
                        "state_write_result_ref"
                    ),
                    "state_write_status_ref": state_write_proof.get(
                        "state_write_status_ref"
                    ),
                    "project_state_ref": state_write_proof.get("project_state_ref"),
                    "primary_recovery_command": recovery.get("primary_command"),
                    "status_after_recovery_command": recovery.get(
                        "status_after_recovery_command"
                    ),
                    "recovery_ref": (
                        "front_door.project_state.recovery"
                        if recovery
                        else None
                    ),
                    "recovery": recovery,
                    "observe_ref": state_write_proof.get("observe_ref"),
                    "reader_action": state_write_proof.get(
                        "reader_action",
                        "Run microcosm tour --card <project>, then rerun status.",
                    ),
                }
            )
        else:
            detail["reader_action"] = (
                "Open the matching status card surface or full status drilldown."
            )
        blocking_surface_details[surface_id] = detail
    return {
        "schema_version": "microcosm_status_card_front_door_status_v1",
        "status": PASS if not blocking_surface_ids else "blocked",
        "surface_statuses": surfaces,
        "blocking_surface_ids": blocking_surface_ids,
        "blocking_surface_details": blocking_surface_details,
        "accepted_nonblocking_statuses": [PASS, "clear", "actionable"],
        "actionable_surface_ids": actionable_surface_ids,
        "drilldown_warning_surface_ids": ["authority", "intake"],
        "drilldown_blocked_surface_ids_status": (
            "not_evaluated_in_status_card"
        ),
        "drilldown_blocked_surface_ids_ref": (
            "microcosm tour <project>::front_door_status."
            "drilldown_blocked_surface_ids"
        ),
        "top_level_status_rule": (
            "pass_when_required_surfaces_are_nonblocking; tour reports "
            "authority/intake warning blockers"
        ),
        "safe_to_show": {
            "surface_status_ids_visible": True,
            "blocking_surface_ids_visible": True,
            "blocking_surface_details_visible": True,
            "drilldown_warning_surface_ids_visible": True,
            "drilldown_blocked_surface_ids_visible_by_ref": True,
            "source_files_mutated_visible": True,
        },
    }


def _project_command_ref(project_path: str | Path) -> str:
    text = str(project_path).strip()
    return text or "<project>"


def _public_project_command_ref(project_path: str | Path, root: Path) -> str:
    path = Path(project_path)
    project_ref = _public_relative(path, root)
    if project_ref.startswith("/") or project_ref.startswith(".."):
        project_ref = path.name
    return _project_command_ref(project_ref)


def _replace_project_placeholder(value: Any, project_ref: str) -> Any:
    if isinstance(value, str):
        return value.replace("<project>", project_ref)
    if isinstance(value, list):
        return [_replace_project_placeholder(item, project_ref) for item in value]
    if isinstance(value, dict):
        return {
            key: _replace_project_placeholder(item, project_ref)
            for key, item in value.items()
        }
    return value


