        def row(label: str, value: Any) -> str:
            return (
                "<tr>"
                f"<th>{html.escape(label)}</th>"
                f"<td>{html.escape(_safe_text(value))}</td>"
                "</tr>"
            )

        def list_text(values: Any) -> str:
            if not isinstance(values, list):
                return ""
            if not values:
                return "none"
            return ", ".join(str(value) for value in values)

        def dict_text(values: Any) -> str:
            if not isinstance(values, dict):
                return ""
            if not values:
                return "none"
            return ", ".join(f"{key}: {value}" for key, value in sorted(values.items()))

        def binding_rows(rows: list[Any], id_key: str) -> str:
            if not rows:
                return "<p class=\"muted\">No bindings yet.</p>"
            items = []
            for item in rows:
                if not isinstance(item, dict):
                    continue
                status = "resolved" if item.get("resolved") is True else "unresolved"
                items.append(
                    "<li>"
                    f"<strong>{html.escape(_safe_text(item.get(id_key)))}</strong>"
                    f" <span class=\"pill {status}\">{status}</span>"
                    f"<br><span class=\"muted\">{html.escape(_safe_text(item.get('title') or item.get('state_ref')))}</span>"
                    "</li>"
                )
            return f"<ul>{''.join(items)}</ul>"

        def first_screen_reader_route_cards() -> str:
            if not first_screen_reader_routes:
                return "<p class=\"muted\">No reader routes in the first-screen card.</p>"
            cards = []
            for route in first_screen_reader_routes:
                route_id = _safe_text(route.get("reader_route_id"))
                packet = reader_packet_by_id.get(route_id, {})
                exit_row = reader_exit_by_id.get(route_id, {})
                label = _safe_text(
                    reader_labels.get(route_id) or route_id.replace("_", " ").title()
                )
                commands = route.get("next_commands", [])
                if not isinstance(commands, list):
                    commands = []
                command_html = "".join(
                    f"<code>{html.escape(_safe_text(command))}</code>"
                    for command in commands[:3]
                )
                focus = route.get("evidence_focus", [])
                if not isinstance(focus, list):
                    focus = []
                focus_html = "".join(
                    f"<li>{html.escape(_safe_text(item))}</li>" for item in focus[:3]
                )
                if focus_html:
                    focus_html = f"<ul>{focus_html}</ul>"
                cards.append(
                    "<article class=\"reader-route-card\">"
                    f"<h3>{html.escape(label)}</h3>"
                    f"<p class=\"reader-question\">{html.escape(_safe_text(route.get('first_question')))}</p>"
                    "<dl>"
                    f"<dt>First action</dt><dd>{html.escape(_safe_text(packet.get('first_action')))}</dd>"
                    f"<dt>Proof surface</dt><dd>{html.escape(_safe_text(packet.get('proof_surface')))}</dd>"
                    f"<dt>Success criterion</dt><dd>{html.escape(_safe_text(packet.get('success_criterion')))}</dd>"
                    f"<dt>Exit when</dt><dd>{html.escape(_safe_text(exit_row.get('exit_when')))}</dd>"
                    "</dl>"
                    f"<div class=\"command-stack\">{command_html}</div>"
                    f"{focus_html}"
                    "</article>"
                )
            return (
                "<div class=\"reader-route-grid\" aria-label=\"Reader route choices\">"
                f"{''.join(cards)}"
                "</div>"
            )

        def first_screen_demo_to_scale_cards() -> str:
            state_file_count = _safe_text(state_inspection.get("state_file_count"))
            state_inspection_status = _safe_text(state_inspection.get("status"))
            public_safe_material_count = _safe_text(
                source_open_body_import_floor.get("public_safe_body_material_count")
            )
            python_file_count = _safe_text(project_python_lens.get("python_file_count"))
            class_counts = dict_text(
                source_open_body_import_floor.get(
                    "public_safe_body_material_counts_by_class"
                )
            )
            if not class_counts:
                class_counts = "class counts not projected"
            authority_boundary = _safe_text(
                source_open_body_import_floor.get("authority_boundary")
                or route.get("authority")
                or causal.get("authority_boundary")
            )
            rows = [
                {
                    "title": "Local demo",
                    "body": (
                        "Runs against your folder and writes inspectable "
                        ".microcosm state refs before any drilldown."
                    ),
                    "proof": (
                        f"State inspection: {state_inspection_status or 'not projected'}; "
                        f"{state_file_count or '0'} state files"
                    ),
                    "endpoint": "/project/observatory-card",
                },
                {
                    "title": "Structural scale",
                    "body": (
                        "The same surface points past the demo into the route, "
                        "graph, Python lens, and source-open body floor."
                    ),
                    "proof": (
                        f"{public_safe_material_count or '0'} public-safe body "
                        f"materials; {python_file_count or '0'} Python files"
                    ),
                    "endpoint": "/project/status",
                },
                {
                    "title": "Evidence floor",
                    "body": (
                        "Counts are honest accounting fields, not maturity "
                        "scores or release claims."
                    ),
                    "proof": class_counts,
                    "endpoint": "/project/evidence",
                },
                {
                    "title": "Authority boundary",
                    "body": (
                        "The local run proves inspectability; it does not "
                        "claim release or private-root equivalence."
                    ),
                    "proof": authority_boundary or "authority ceiling not projected",
                    "endpoint": "/authority",
                },
            ]
            cards = []
            for item in rows:
                cards.append(
                    "<article class=\"scale-bridge-card\">"
                    f"<h3>{html.escape(item['title'])}</h3>"
                    f"<p>{html.escape(item['body'])}</p>"
                    f"<strong>{html.escape(item['proof'])}</strong>"
                    f"<code>{html.escape(item['endpoint'])}</code>"
                    "</article>"
                )
            return (
                "<div class=\"scale-bridge-grid\" aria-label=\"Demo to scale bridge\">"
                f"{''.join(cards)}"
                "</div>"
            )

